using System;
using System.Reflection;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace MyApp.Tests;

public sealed class TimedTestMethodAttribute : TestMethodAttribute
{
    private readonly int _warningThresholdMs;

    public TimedTestMethodAttribute(int warningThresholdMs = 5000)
    {
        _warningThresholdMs = warningThresholdMs;
    }
}

[AttributeUsage(AttributeTargets.Assembly)]
public sealed class TimedTestMethodFixtureAttribute : Attribute, ITestMethodLifecycle
{
    public Task OnTestMethodStartAsync(TestMethodContext context)
    {
        context.TestMethod.SetPropertyValue(new TestProperty("TimedTest_Start", typeof(long).FullName!), System.Diagnostics.Stopwatch.GetTimestamp());
        return Task.CompletedTask;
    }

    public Task OnTestMethodEndAsync(TestMethodContext context)
    {
        if (context.TestMethod.GetAttributes<TimedTestMethodAttribute>(false) is { Length: > 0 } attrs)
        {
            var attr = attrs[0];
            var thresholdMs = (int)(attr.GetType()
                .GetField("_warningThresholdMs", BindingFlags.NonPublic | BindingFlags.Instance)!
                .GetValue(attr)!);
            var start = (long)context.TestMethod.GetPropertyValue(new TestProperty("TimedTest_Start", typeof(long).FullName!))!;
            var elapsedMs = System.Diagnostics.Stopwatch.GetElapsedTime(start).TotalMilliseconds;

            if (elapsedMs > thresholdMs)
            {
                Console.WriteLine($"WARNING: {context.TestMethod.TestMethodName} took {elapsedMs:F0}ms (threshold: {thresholdMs}ms)");
            }
        }

        return Task.CompletedTask;
    }
}

